<script setup lang="ts">import{onMounted,ref}from"vue";import{useRoute,useRouter}from"vue-router";import{MessageCircle,ShieldCheck,CalendarDays}from"lucide-vue-next";import{api,type Doctor,type Schedule}from"../api";import PageHeader from"../components/PageHeader.vue";const route=useRoute(),router=useRouter(),doctor=ref<Doctor>(),schedules=ref<Schedule[]>([]);const period:Record<string,string>={morning:"上午",afternoon:"下午",evening:"晚上",custom:"其他"};onMounted(async()=>{const id=Number(route.params.id);[doctor.value,schedules.value]=await Promise.all([api.doctor(id),api.schedules(id)])});</script><template><main v-if="doctor"><PageHeader title="医生主页"/><section class="doctor-profile"><div class="large-avatar">{{doctor.name[0]}}</div><div><h1>{{doctor.name}} <small>{{doctor.title}}</small></h1><p>{{doctor.departmentName}}</p><p>{{doctor.hospitalName}}</p></div><div class="profile-tags"><span>平台认证</span><span>专业资质</span><span>实时号源</span></div></section><section class="doctor-intro"><h2>医生简介</h2><p>{{doctor.description||`${doctor.name}医生长期从事${doctor.departmentName}临床诊疗工作。`}}</p><h2>专业擅长</h2><p>{{doctor.specialty}}</p><small>提示：医生排班和费用以预约页面实际号源为准。</small></section><div class="consult-banner"><MessageCircle/><b>有问题，请电话咨询</b><button>电话咨询</button></div><section class="schedule-section"><header><h2>出诊信息</h2><span><ShieldCheck/> 挂号须知</span></header><article v-for="s in schedules" :key="s.id" class="schedule-card"><div><b>{{s.scheduleDate}} · {{period[s.period]}}</b><small>{{s.startTime}}–{{s.endTime}}　剩余 {{s.availableSlots}} 号</small></div><strong>¥{{s.fee}}</strong><button :disabled="!s.availableSlots" @click="router.push(`/booking/${doctor.id}/${s.id}`)">预约挂号</button></article><div v-if="!schedules.length" class="empty"><CalendarDays/>暂无有效排班</div></section></main>
</template>
